        while self.peek() and self.is_digit(self.peek()):
            num_str += self.advance()

        # Check for decimal part
        if self.peek() == '.':
            num_str += self.advance()  # consume '.'
            # Read fractional part
            while self.peek() and self.is_digit(self.peek()):
                num_str += self.advance()

        value = float(num_str)
        return Token('NUMBER', value, start_line, start_col)

